/**
 * Um turno da conversa de refino por IA (auditoria).
 */
export interface TurnoConversaIa {
  instrucao: string;
  criadoEm: string;
}

/**
 * Uma geração de contrato da paciente (rascunho → aprovado → enviado).
 */
export interface ContratoGeracao {
  id: number;
  pacienteId: number;
  tipo: DocumentoTipo;
  /** @nullable */
  modeloId: number | null;
  modeloProcedimento: string;
  modeloVersao: number;
  titulo: string;
  corpo: string;
  /** Caminho do PDF no armazenamento quando o contrato foi enviado PRONTO por fora (upload). null nas gerações produzidas pelo motor. */
  arquivoObjectPath: string | null;
  /** Nome original do arquivo enviado (upload). null nas gerações do motor. */
  arquivoNome: string | null;
  /** Signatários enviados à Autentique (papel + nome + e-mail). null enquanto não enviado ou em envios antigos (signatário único). */
  signatarios: SignatarioInput[] | null;
  relatorioIa: RelatorioRevisao | null;
  decisoes: DecisaoRegiao[] | null;
  /** Via de criação (template = motor de cláusulas; upload = PDF pronto; ia = redigido por IA). */
  origem: ContratoGeracaoOrigem;
  /** Snapshot do formulário da via de IA. null nas demais vias. */
  formularioIa: FormularioDocumentoIa | null;
  /** Trilha das instruções de refino por IA aplicadas ao corpo. */
  conversaIa: TurnoConversaIa[] | null;
  iaRevisadoEm: string | null;
  status: ContratoGeracaoStatus;
  aprovadoPor: string | null;
  aprovadoEm: string | null;
  autentiqueId: string | null;
  erroEnvio: string | null;
  createdAt: string;
  updatedAt: string;
}

/**
 * Gera um documento redigido por IA a partir do formulário.
 */
export interface GerarIaInput {
  tipo: DocumentoTipo;
  formulario: FormularioDocumentoIa;
}

/**
 * Aplica uma instrução de alteração a um documento redigido por IA.
 */
export interface RefinarIaInput {
  /** @minLength 1 */
  instrucao: string;
}

/**
 * Gera um rascunho a partir do modelo-base vigente do tipo pedido. Aceita as decisões escolhidas no wizard e, opcionalmente, o CORPO já revisado/editado pelo operador (etapa "Revisar texto"); quando presente, é persistido como o texto do rascunho em vez de resolver o modelo do zero.
 */
export interface GerarContratoInput {
  tipo: DocumentoTipo;
  /** Corpo já revisado (etapa de texto). Ausente = resolver do modelo. */
  corpo?: string;
  decisoes?: DecisaoRegiaoInput[];
}

export interface EditarContratoBody {
  /** @minLength 1 */
  corpo: string;
}

export interface DefinirDecisoesBody {
  decisoes: DecisaoRegiaoInput[];
}

export interface RevisarPreviaInput {
  tipo: DocumentoTipo;
  titulo: string;
  /** @minLength 1 */
  corpo: string;
}

export interface AprovarContratoBody {
  /**
     * Nome de quem aprova (auditoria da etapa humana obrigatória).
     * @minLength 1
     */
  aprovadoPor: string;
  /** E-mail do signatário (legado, signatário único); sem ele a Autentique usa entrega por link. */
  email?: string;
  /** Signatários configurados no envio (contrato: paciente + representante legal; termo: paciente + médico). Quando presente, tem precedência sobre `email`. */
  signatarios?: SignatarioInput[];
}

